            catch (Exception ex)
            {
                // Token validation failed for other reasons (e.g., invalid signature, issuer, audience).
                // Log the exception for debugging.
                Console.WriteLine($"JWT Token validation failed: {ex.Message}");
            }
        }
    }
}

