namespace YourApp.Authentication
{
    public static class JwtMiddlewareExtensions
    {
        public static IServiceCollection AddJwtAuthentication(this IServiceCollection services, IConfiguration configuration)
        {
            // Configure JwtSettings from appsettings.json
            services.Configure<JwtSettings>(configuration.GetSection("JwtSettings"));

            // Add the custom middleware as a transient service
            services.AddTransient<JwtMiddleware>();

            return services;
        }

        public static IApplicationBuilder UseJwtAuthentication(this IApplicationBuilder app)
        {
            // Use the custom middleware in the request pipeline
            return app.UseMiddleware<JwtMiddleware>();
        }
    }
